const event = $input.first().json.body;

if (event.type !== 'checkout.session.completed') {
  return [{json: {status: 'ignored', reason: event.type}}];
}

const session = event.data.object;
const metadata = session.metadata || {};

let formData = {};
try {
  if (session.client_reference_id) {
    formData = JSON.parse(atob(session.client_reference_id));
  }
} catch (e) {
  console.log('Decode error:', e);
}

const clientId = formData.business_name?.replace(/\s+/g, '-').toUpperCase() 
  || metadata.client_id 
  || session.customer_details?.email?.split('@')[0]?.toUpperCase() 
  || 'UNKNOWN';

return [{
  json: {
    client_id: clientId,
    business_name: formData.business_name || 'Unknown',
    customer_email: session.customer_details?.email || formData.email || '',
    customer_name: session.customer_details?.name || formData.business_name || '',
    stripe_subscription_id: session.subscription,
    stripe_session_id: session.id,
    billing_period: metadata.billing || 'monthly',
    tier: 'enterprise',
    compliance: (formData.compliance || ['SOC2']).join(','),
    locations: (formData.locations || [formData.primary_region || 'ord']).join(','),
    primary_region: formData.primary_region || 'ord',
    industry: formData.industry || 'general',
    brand_color: formData.brand_color || '#001a2d',
    status: 'checkout_complete'
  }
}];
